public class Main {
    public static void main(String[] args) {

        // Widening: int → double (automatic)
        int    marks  = 87;
        double dMarks = marks;               // no cast needed
        System.out.printf("int to double: %.1f%n", dMarks); // 87.0

        // Narrowing: double → int (explicit cast, truncates)
        double avg  = 73.89;
        int    iAvg = (int) avg;             // 73 — decimal dropped
        int    rAvg = (int) Math.round(avg); // 74 — nearest integer
        System.out.println("Truncated: " + iAvg);
        System.out.println("Rounded  : " + rAvg);

        // char ↔ int (char stores Unicode code point)
        char   letter = 'A';
        int    code   = letter;              // 65 (widening)
        char   back   = (char)(code + 1);   // 'B' (narrowing cast)
        System.out.println("char to int: " + code);
        System.out.println("int to char: " + back);

        // String → number parsing
        String scoreStr = "92";
        int    score    = Integer.parseInt(scoreStr);
        System.out.println("Parsed int: " + (score + 8)); // 100

        // Number → String
        String label = "Score: " + String.valueOf(score);
        System.out.println(label);
    }
}

